const today = new Date("2026-05-26"); // System baseline time reference
const webhookBody = $('Bubble Webhook Trigger').first().json.body;

// We support either full payload ingestion directly from Bubble or dynamic fetching.
// For the primary path, we parse the structured webhookBody.
let author = webhookBody;

const name = author.name || "Author";
const email = author.email || "";
const authorId = author.author_id || author.unique_id || "";
const city = author.city || "";
const books = author.books || [];
const logId = $('Create Processing Log').first().json.response?.id || "";

let totalEarned = 0;
let totalPaid = 0;
let totalPending = 0;
let bookList = [];

for (const book of books) {
  const earned = book.total_royalty_earned || 0;
  const paid = book.royalty_paid || 0;
  const pending = book.royalty_pending || 0;
  totalEarned += earned;
  totalPaid += paid;
  totalPending += pending;

  // Royalty Status Indicator Rules:
  // - Green: pending is 0 (fully paid)
  // - Yellow: pending > 0 but within normal cycle (last payout is within 90 days or brand new published book < 90 days)
  // - Red: pending > 0 AND (last payout > 90 days ago OR no payout ever made for a published book older than 90 days)
  let status = "Green";
  let reason = "All royalties fully paid up.";

  if (pending > 0) {
    status = "Yellow";
    reason = "Pending royalty within the standard payout cycle.";

    if (book.last_royalty_payout_date) {
      const lastPayout = new Date(book.last_royalty_payout_date);
      const diffTime = Math.abs(today - lastPayout);
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      if (diffDays > 90) {
        status = "Red";
        reason = `Royalty pending and last payout was ${diffDays} days ago (exceeds 90-day threshold).`;
      }
    } else if (book.publication_date && book.status === "Published & Live") {
      const pubDate = new Date(book.publication_date);
      const diffTime = Math.abs(today - pubDate);
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      if (diffDays > 90) {
        status = "Red";
        reason = `Published ${diffDays} days ago, pending royalties exist, and no payout has ever been made (exceeds 90-day threshold).`;
      }
    }
  }

  bookList.push({
    book_id: book.book_id,
    title: book.title,
    isbn: book.isbn,
    genre: book.genre,
    status: book.status,
    publication_date: book.publication_date || "N/A",
    mrp: book.mrp || null,
    copies_sold: book.total_copies_sold || 0,
    earned: earned,
    paid: paid,
    pending: pending,
    last_payout: book.last_royalty_payout_date || "None",
    print_partner: book.print_partner || "N/A",
    payout_status: status,
    payout_status_reason: reason
  });
}

return [{
  json: {
    author_id: authorId,
    name: name,
    email: email,
    city: city,
    log_id: logId,
    summary: {
      total_books: books.length,
      published_books: bookList.filter(b => b.status === "Published & Live").length,
      production_books: bookList.filter(b => b.status !== "Published & Live").length,
      total_earned: totalEarned,
      total_paid: totalPaid,
      total_pending: totalPending,
      has_overdue: bookList.some(b => b.payout_status === "Red")
    },
    books: bookList,
    payout_policy: {
      cycle: "Quarterly (45 days after calendar quarter close)",
      rule: "Royalties for Q1 (Jan-Mar) are paid by May 15, Q2 (Apr-Jun) by Aug 15, Q3 (Jul-Sep) by Nov 15, and Q4 (Oct-Dec) by Feb 15 of the following year."
    }
  }
}];

